use std::collections::HashMap;

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut ans = Vec::new();
    for query in queries {
        let li = query[0] as usize;
        let ri = query[1] as usize;
        let threshold = query[2] as usize;
        let sub = &nums[li..ri + 1];
        let mut freq = HashMap::new();
        for num in sub {
            *freq.entry(*num).or_insert(0) += 1;
        }
        let candidates: Vec<_> = freq.iter()
            .filter(|&(_, count)| count >= threshold)
            .collect();
        if candidates.is_empty() {
            ans.push(-1);
        } else {
            let mut max_freq = 0;
            let mut best_num = -1;
            for (key, value) in candidates {
                let key = *key;
                let value = *value;
                if value > max_freq || (value == max_freq && key < best_num) {
                    max_freq = value;
                    best_num = key;
                }
            }
            ans.push(best_num);
        }
    }
    ans
}
