use std::collections::HashMap;

pub fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut ans = Vec::new();
    for query in queries {
        let li = query[0] as usize;
        let ri = query[1] as usize;
        let threshold = query[2] as usize;
        let subarray = &nums[li..ri + 1];
        let mut freq = HashMap::new();
        for &num in subarray {
            *freq.entry(num).or_insert(0) += 1;
        }
        let mut candidates = Vec::new();
        for (k, v) in &freq {
            if *v >= threshold {
                candidates.push((k.clone(), *v));
            }
        }
        if candidates.is_empty() {
            ans.push(-1);
