            let mut max_freq = 0;
            let mut best_num = i64::MAX;
            for (num, count) in candidates {
                if count > max_freq || (count == max_freq && num < best_num) {
                    max_freq = *count;
                    best_num = num;
                }
            }
            ans.push(best_num);
        }
    }
    ans
}
